const T={bg:"#07080c",bg2:"#0c0e14",sf:"#11131b",sf2:"#171b27",sf3:"#1d2234",bd:"#1a1e30",bd2:"#252b42",gn:"#22c55e",gn2:"#4ade80",gnA:"rgba(34,197,94,.10)",gnA2:"rgba(34,197,94,.22)",pr:"#7c3aed",pr2:"#a78bfa",prA:"rgba(124,58,237,.10)",rd:"#ef4444",rd2:"#f87171",rdA:"rgba(239,68,68,.10)",or:"#f59e0b",or2:"#fbbf24",orA:"rgba(245,158,11,.10)",bl:"#3b82f6",bl2:"#60a5fa",blA:"rgba(59,130,246,.10)",tl:"#14b8a6",tlA:"rgba(20,184,166,.10)",pk:"#ec4899",pkA:"rgba(236,72,153,.10)",yl:"#eab308",tx:"#f1f5f9",tx2:"#94a3b8",tx3:"#64748b",tx4:"#334155"};
const F=`'Inter','SF Pro Display',system-ui,sans-serif`;
const M=`'JetBrains Mono','SF Mono',monospace`;
const CSS=`@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap');*{box-sizing:border-box;margin:0;padding:0}::-webkit-scrollbar{width:5px}::-webkit-scrollbar-thumb{background:${T.bd2};border-radius:3px}::-webkit-scrollbar-track{background:transparent}input::placeholder,textarea::placeholder{color:${T.tx4}}@keyframes fadeUp{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}@keyframes pulse{0%,100%{opacity:1}50%{opacity:.35}}@keyframes spin{to{transform:rotate(360deg)}}@keyframes glow{0%,100%{box-shadow:0 0 8px rgba(124,58,237,.12)}50%{box-shadow:0 0 20px rgba(124,58,237,.25)}}.fu{animation:fadeUp .45s cubic-bezier(.16,1,.3,1) both}.s1{animation-delay:.04s}.s2{animation-delay:.08s}.s3{animation-delay:.12s}.s4{animation-delay:.16s}.s5{animation-delay:.2s}.s6{animation-delay:.24s}`;

// ── Primitives ──
function Bdg({children,c="gn",sz="sm",s={}}){const m={gn:[T.gnA,T.gn2],pr:[T.prA,T.pr2],rd:[T.rdA,T.rd2],or:[T.orA,T.or2],bl:[T.blA,T.bl2],tl:[T.tlA,T.tl],pk:[T.pkA,T.pk]}[c]||[T.gnA,T.gn2];const p=sz==="xs"?"2px 6px":sz==="lg"?"5px 14px":"3px 9px";const f=sz==="xs"?10:sz==="lg"?12:11;return <span style={{background:m[0],color:m[1],padding:p,borderRadius:5,fontSize:f,fontWeight:600,whiteSpace:"nowrap",display:"inline-flex",alignItems:"center",gap:3,...s}}>{children}</span>;}

function Crd({children,style={},onClick,className=""}){return <div className={className} onClick={onClick} style={{background:T.sf,border:`1px solid ${T.bd}`,borderRadius:10,padding:20,transition:"border-color .15s",cursor:onClick?"pointer":"default",...style}} onMouseEnter={e=>{if(onClick)e.currentTarget.style.borderColor=T.bd2}} onMouseLeave={e=>{e.currentTarget.style.borderColor=T.bd}}>{children}</div>;}

function Btn({children,v="default",sz="sm",onClick,disabled,s={}}){const vars={primary:{bg:T.pr,c:"#fff",bd:"none"},cta:{bg:T.rd,c:"#fff",bd:"none"},danger:{bg:"transparent",c:T.rd2,bd:`1px solid ${T.rd}35`},success:{bg:T.gnA2,c:T.gn2,bd:`1px solid ${T.gn}35`},ghost:{bg:"transparent",c:T.tx2,bd:`1px solid ${T.bd}`},default:{bg:T.sf2,c:T.tx2,bd:`1px solid ${T.bd}`}}[v]||{bg:T.sf2,c:T.tx2,bd:`1px solid ${T.bd}`};const p=sz==="xs"?"4px 8px":sz==="lg"?"11px 24px":"6px 13px";const f=sz==="xs"?11:sz==="lg"?14:12;return <button onClick={onClick} disabled={disabled} style={{background:vars.bg,color:disabled?T.tx4:vars.c,border:vars.bd,borderRadius:6,padding:p,fontSize:f,fontWeight:600,cursor:disabled?"default":"pointer",fontFamily:F,transition:"all .12s",...s}}>{children}</button>;}

function PB({pct,color=T.gn,h=6}){return <div style={{flex:1,height:h,background:T.sf3,borderRadius:h,overflow:"hidden"}}><div style={{height:"100%",width:`${pct}%`,background:color,borderRadius:h,transition:"width 1s cubic-bezier(.16,1,.3,1)"}}/></div>;}

function CS({score,sz=88}){const r=(sz-10)/2,c=2*Math.PI*r,off=c-(score/100)*c;const col=score>=80?T.gn:score>=60?T.or:score>=40?T.or:T.rd;const gr=score>=90?"A":score>=80?"B":score>=70?"C":score>=60?"D":"F";return <div style={{position:"relative",width:sz,height:sz}}><svg width={sz} height={sz} style={{transform:"rotate(-90deg)"}}><circle cx={sz/2} cy={sz/2} r={r} fill="none" stroke={T.sf3} strokeWidth={5}/><circle cx={sz/2} cy={sz/2} r={r} fill="none" stroke={col} strokeWidth={5} strokeDasharray={c} strokeDashoffset={off} strokeLinecap="round" style={{transition:"stroke-dashoffset 1.5s cubic-bezier(.16,1,.3,1)"}}/></svg><div style={{position:"absolute",inset:0,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center"}}><span style={{fontSize:sz*.28,fontWeight:800,color:col,lineHeight:1}}>{score}</span><span style={{fontSize:9,color:T.tx4,fontWeight:700,marginTop:1}}>{gr}</span></div></div>;}

function Lbl({children}){return <div style={{fontSize:10,fontWeight:700,color:T.tx4,letterSpacing:1.2,textTransform:"uppercase",marginBottom:12}}>{children}</div>;}
function Spinner({sz=13,c=T.pr2}){return <div style={{width:sz,height:sz,border:`2px solid ${T.sf3}`,borderTopColor:c,borderRadius:"50%",animation:"spin .6s linear infinite"}}/>;}

// ── Pipeline ──
const LOGS=[["Parsing feature description...","Extracting domain context...","Generating release spec...","Identifying personas & stories...","Scoring risks...","Building checklist...","Navigator complete → handoff"],["Analysing spec for edge cases...","Generating test strategy...","Creating test cases...","Defining guardrails...","Sentinel complete → handoff"],["Synthesising release notes...","Generating GTM copy...","Building pitch deck...","Herald complete"]];

function Pipeline({phase,showLogs=false}){
  const ag=[{n:"Navigator",c:T.gn},{n:"Sentinel",c:T.pr2},{n:"Herald",c:T.or2}];
  const[logs,setLogs]=useState([]);
  useEffect(()=>{if(!showLogs||phase<0||phase>2)return;const ls=LOGS[phase]||[];let i=0;const iv=setInterval(()=>{if(i<ls.length){setLogs(p=>[...p.slice(-10),{t:new Date().toISOString().slice(11,19),m:ls[i],p:phase}]);i++;}else clearInterval(iv);},500);return()=>clearInterval(iv);},[phase,showLogs]);
  return <div><div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:0,padding:"12px 0"}}>{ag.map((a,i)=>{const done=phase>i,act=phase===i;return <div key={i} style={{display:"flex",alignItems:"center"}}>{i>0&&<div style={{width:40,height:2,background:done?a.c+"60":T.bd,transition:"all .4s"}}/>}<div style={{display:"flex",alignItems:"center",gap:5,padding:"6px 12px",borderRadius:7,border:`1px solid ${done?a.c+"50":act?a.c:T.bd}`,background:done?a.c+"0a":act?a.c+"08":"transparent",animation:act?"glow 2s ease infinite":"none"}}>{done&&<span style={{color:T.gn,fontSize:11,fontWeight:700}}>✓</span>}{act&&<Spinner sz={11} c={a.c}/>}<div><div style={{fontSize:12,color:done||act?a.c:T.tx4,fontWeight:600}}>{a.n}</div></div></div></div>;})}{phase>=3&&<Bdg c="gn" s={{marginLeft:10}}>✓ COMPLETE</Bdg>}</div>{showLogs&&logs.length>0&&<div style={{background:T.bg2,border:`1px solid ${T.bd}`,borderRadius:7,padding:"8px 12px",marginTop:6,maxHeight:120,overflow:"auto",fontFamily:M,fontSize:11}}>{logs.map((l,i)=><div key={i} style={{padding:"2px 0",color:l.p===0?T.gn:l.p===1?T.pr2:T.or2,opacity:i===logs.length-1?1:.5}}><span style={{color:T.tx4,marginRight:8}}>{l.t}</span>{l.m}</div>)}</div>}</div>;
}

// ── Heatmap ──
function Heatmap({risks}){const lvl=["Low","Medium","High"];const mx={};lvl.forEach(l=>lvl.forEach(i=>{mx[`${l}-${i}`]=[];}));risks.forEach(r=>{const k=`${r.likelihood||"Medium"}-${r.impact||"High"}`;if(mx[k])mx[k].push(r);});const cc=(l,i)=>{const s=lvl.indexOf(l)+lvl.indexOf(i);return s>=3?T.rdA:s>=2?T.orA:T.gnA;};return <div><div style={{display:"grid",gridTemplateColumns:"50px repeat(3,1fr)",gap:2}}><div/>{lvl.map(l=><div key={l} style={{textAlign:"center",fontSize:9,fontWeight:600,color:T.tx4,padding:"5px 0"}}>{l}</div>)}{[...lvl].reverse().map(lik=><div key={lik} style={{display:"contents"}}><div style={{display:"flex",alignItems:"center",justifyContent:"flex-end",paddingRight:6,fontSize:9,fontWeight:600,color:T.tx4}}>{lik}</div>{lvl.map(imp=>{const items=mx[`${lik}-${imp}`];return <div key={`${lik}-${imp}`} style={{background:items.length?cc(lik,imp):T.sf2,border:`1px solid ${T.bd}`,borderRadius:5,padding:5,minHeight:36}}>{items.map((r,i)=><div key={i} style={{fontSize:9,color:T.tx2}}>{r.n.slice(0,25)}</div>)}</div>;})}</div>)}</div></div>;}

